import stylesText from './meal-log-detail.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { formatMacro } from '../../../utils/format-macro.js';
import {
    MEAL_TYPES,
    type MealType,
    type MealWithIngredients,
    computeSnapshotMacros,
} from '@motivation/shared';
import {
    createFoodLogBackEvent,
    createLogMealEvent,
} from '../health-events.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <div class="meal-detail">
        <div class="meal-header">
            <h3 class="meal-name" id="meal-name"></h3>
            <span class="meal-notes" id="meal-notes"></span>
        </div>

        <div class="scale-row">
            <label for="meal-scale">Scale</label>
            <input type="number" id="meal-scale" min="0.1" step="0.1">
            <span id="scale-hint" class="meal-notes"></span>
        </div>

        <div class="meal-type-row">
            <label for="meal-type">Meal</label>
            <select id="meal-type">
                ${MEAL_TYPES.map(m => `<option value="${m}">${m}</option>`).join('\n                ')}
            </select>
        </div>

        <ul class="ingredient-list" id="ingredient-list"></ul>

        <div class="totals">
            <span class="total-cal"><span id="total-cal">0</span> kcal</span>
            <span>P: <span id="total-p">0</span>g</span>
            <span>C: <span id="total-c">0</span>g</span>
            <span>F: <span id="total-f">0</span>g</span>
        </div>

        <div class="actions">
            <button class="btn-back" id="back-btn">← Back</button>
            <button class="btn-log" id="log-btn">Log Meal</button>
        </div>
    </div>
`;

export class MealLogDetail extends HTMLElement {
    private mealValue: MealWithIngredients | null = null;
    private defaultMealTypeValue: MealType | null = null;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback(): void {
        const shadow = this.shadowRoot!;
        shadow.getElementById('back-btn')!.addEventListener('click', () => this.dispatchEvent(createFoodLogBackEvent()));
        shadow.getElementById('log-btn')!.addEventListener('click', () => this.handleLog());
        shadow.getElementById('meal-scale')!.addEventListener('input', () => this.renderTotals());
        this.applyMealTypeSelection();
    }

    set defaultMealType(mealType: string | null) {
        if (!mealType || !MEAL_TYPES.includes(mealType as MealType)) {
            this.defaultMealTypeValue = null;
        } else {
            this.defaultMealTypeValue = mealType as MealType;
        }
        this.applyMealTypeSelection();
    }

    showMeal(meal: MealWithIngredients): void {
        this.mealValue = meal;
        const shadow = this.shadowRoot!;
        shadow.getElementById('meal-name')!.textContent = meal.name;
        shadow.getElementById('meal-notes')!.textContent = meal.notes ?? '';

        const scaleInput = shadow.getElementById('meal-scale') as HTMLInputElement;
        scaleInput.value = String(meal.default_scale);
        shadow.getElementById('scale-hint')!.textContent = meal.default_scale === 1 ? '' : `(default ${meal.default_scale}×)`;

        this.applyMealTypeSelection();
        this.renderIngredientList();
        this.renderTotals();
    }

    private applyMealTypeSelection(): void {
        const select = this.shadowRoot?.getElementById('meal-type') as HTMLSelectElement | null;
        if (!select) return;
        if (this.defaultMealTypeValue) {
            select.value = this.defaultMealTypeValue;
        }
    }

    private renderIngredientList(): void {
        if (!this.mealValue) return;
        const list = this.shadowRoot!.getElementById('ingredient-list')!;
        list.replaceChildren();
        const scale = this.getCurrentScale();
        for (const ing of this.mealValue.ingredients) {
            const amount = ing.amount * scale;
            const macros = computeSnapshotMacros(ing.food_item, amount);
            const li = document.createElement('li');
            li.className = 'ingredient-row';
            const name = document.createElement('span');
            name.className = 'ingredient-name';
            name.textContent = ing.food_item.display_name;
            const amt = document.createElement('span');
            amt.className = 'ingredient-amount';
            amt.textContent = `${formatMacro(amount)}${ing.food_item.base_unit}`;
            const cal = document.createElement('span');
            cal.className = 'ingredient-cal';
            cal.textContent = `${formatMacro(macros.calories ?? 0)} kcal`;
            li.appendChild(name);
            li.appendChild(amt);
            li.appendChild(cal);
            list.appendChild(li);
        }
    }

    private renderTotals(): void {
        if (!this.mealValue) return;
        const scale = this.getCurrentScale();
        let cal = 0, p = 0, c = 0, f = 0;
        for (const ing of this.mealValue.ingredients) {
            const macros = computeSnapshotMacros(ing.food_item, ing.amount * scale);
            cal += macros.calories ?? 0;
            p += macros.protein_g ?? 0;
            c += macros.carbs_g ?? 0;
            f += macros.fat_g ?? 0;
        }
        const shadow = this.shadowRoot!;
        shadow.getElementById('total-cal')!.textContent = formatMacro(cal);
        shadow.getElementById('total-p')!.textContent = formatMacro(p);
        shadow.getElementById('total-c')!.textContent = formatMacro(c);
        shadow.getElementById('total-f')!.textContent = formatMacro(f);

        // Re-render the per-ingredient list so its scaled amounts/calories track the slider.
        this.renderIngredientList();
    }

    private getCurrentScale(): number {
        const input = this.shadowRoot?.getElementById('meal-scale') as HTMLInputElement | null;
        if (!input) return this.mealValue?.default_scale ?? 1;
        const parsed = Number.parseFloat(input.value);
        return Number.isFinite(parsed) && parsed > 0 ? parsed : (this.mealValue?.default_scale ?? 1);
    }

    private getSelectedMealType(): MealType {
        const select = this.shadowRoot!.getElementById('meal-type') as HTMLSelectElement;
        return select.value as MealType;
    }

    private handleLog(): void {
        if (!this.mealValue) return;
        this.dispatchEvent(createLogMealEvent({
            meal_id: this.mealValue.id,
            date: '',  // Filled in by the screen, which holds the date.
            meal_type: this.getSelectedMealType(),
            scale: this.getCurrentScale(),
        }));
    }
}

if (!customElements.get('meal-log-detail')) {
    customElements.define('meal-log-detail', MealLogDetail);
}
