import stylesText from './food-log.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import { MEAL_TYPES } from '@motivation/shared';
import type { FoodItem, MealType } from '@motivation/shared';
import type { OFFProduct } from '../../../services/openfoodfacts.service.js';
import { OpenFoodFactsService } from '../../../services/openfoodfacts.service.js';
import { HealthService } from '../../../services/health.service.js';
import {
    HEALTH_EVENTS,
    createFoodLogBackEvent,
    createLogFoodEvent,
    createAddIngredientEvent,
} from '../health-events.js';

export type FoodLogDetailMode = 'log' | 'add-ingredient';
import { getDefaultMealType } from '../health-dashboard/health-utils.js';
import { offProductToFormData, foodItemToFormData } from '../food-serving-form/food-serving-form.types.js';
import '../food-serving-form/food-serving-form.component.js';
import type { FoodServingForm } from '../food-serving-form/food-serving-form.component.js';

const template = document.createElement('template');
template.innerHTML = `
    <div class="product-detail">
        <div class="product-header">
            <img id="product-image" class="product-image" hidden alt="" crossorigin="anonymous">
            <div class="product-info">
                <h3 id="product-name"></h3>
                <div class="brand" id="product-brand"></div>
            </div>
        </div>

        <food-serving-form id="serving-form"></food-serving-form>

        <div class="form-row" id="meal-type-row">
            <div class="form-group">
                <label for="meal-type">Meal</label>
                <select id="meal-type">
                    ${MEAL_TYPES.map(m => `<option value="${m}">${m}</option>`).join('\n                    ')}
                </select>
            </div>
        </div>

        <div class="actions">
            <button class="btn-back" id="back-btn">← Back</button>
            <button class="btn-log" id="log-btn">Log Food</button>
        </div>
    </div>
`;

/**
 * Detail emitted by `food-log-detail` when the user presses "Log Food".
 * Maps cleanly to a NewConsumptionEntry once the screen attaches the date.
 * The food_item is guaranteed to exist on the server by the time this fires
 * — for OFF products the detail component creates it on demand.
 */
export interface FoodLogEntry {
    food_item_id: string;
    meal_type: MealType;
    amount: number;
    calories?: number;
    protein_g?: number;
    carbs_g?: number;
    fat_g?: number;
    fiber_g?: number;
    sugar_g?: number;
    sodium_mg?: number;
}

export class FoodLogDetail extends HTMLElement {
    private productValue: OFFProduct | null = null;
    private libraryItemValue: FoodItem | null = null;
    private defaultMealTypeValue: MealType | null = null;
    private modeValue: FoodLogDetailMode = 'log';

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback(): void {
        const shadow = this.shadowRoot!;
        shadow.getElementById('back-btn')!.addEventListener('click', () => this.dispatchEvent(createFoodLogBackEvent()));
        shadow.getElementById('log-btn')!.addEventListener('click', () => this.handleLog());
        this.applyMealTypeSelection();
        this.applyMode();
    }

    set defaultMealType(mealType: string | null) {
        if (!mealType || !MEAL_TYPES.includes(mealType as MealType)) {
            this.defaultMealTypeValue = null;
            this.applyMealTypeSelection();
            return;
        }
        this.defaultMealTypeValue = mealType as MealType;
        this.applyMealTypeSelection();
    }

    set mode(value: FoodLogDetailMode) {
        this.modeValue = value;
        this.applyMode();
    }

    private applyMode(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const mealRow = shadow.getElementById('meal-type-row');
        const logBtn = shadow.getElementById('log-btn');
        if (mealRow) mealRow.hidden = this.modeValue === 'add-ingredient';
        if (logBtn) logBtn.textContent = this.modeValue === 'add-ingredient' ? 'Add to meal' : 'Log Food';
    }

    showProduct(product: OFFProduct): void {
        this.productValue = product;
        this.libraryItemValue = null;
        const shadow = this.shadowRoot!;
        shadow.getElementById('product-name')!.textContent = product.product_name;
        shadow.getElementById('product-brand')!.textContent = product.brands ?? '';

        const img = shadow.getElementById('product-image') as HTMLImageElement;
        if (product.image_url) {
            img.src = product.image_url;
            img.hidden = false;
        } else {
            img.hidden = true;
            img.src = '';
        }

        (shadow.getElementById('serving-form') as FoodServingForm).data = offProductToFormData(product);
        this.applyMealTypeSelection();
    }

    showLibraryItem(item: FoodItem, initialAmount?: number): void {
        this.libraryItemValue = item;
        this.productValue = null;
        const shadow = this.shadowRoot!;
        shadow.getElementById('product-name')!.textContent = item.display_name;
        shadow.getElementById('product-brand')!.textContent = item.brand ?? '';
        const img = shadow.getElementById('product-image') as HTMLImageElement;
        img.hidden = true;
        img.src = '';

        (shadow.getElementById('serving-form') as FoodServingForm).data = foodItemToFormData(item, initialAmount);
        this.applyMealTypeSelection();
    }

    private async handleLog(): Promise<void> {
        const form = this.shadowRoot!.getElementById('serving-form') as FoodServingForm;
        const { servingAmount, serving } = form.getCurrentValues();

        let foodItem: FoodItem | null = null;

        if (this.libraryItemValue) {
            foodItem = this.libraryItemValue;
        } else if (this.productValue) {
            foodItem = await this.ensureFoodItemForOffProduct(this.productValue);
        }

        if (!foodItem) return;

        if (this.modeValue === 'add-ingredient') {
            this.dispatchEvent(createAddIngredientEvent({ food_item: foodItem, amount: servingAmount }));
            return;
        }

        const detail: FoodLogEntry = {
            food_item_id: foodItem.id,
            meal_type: this.getSelectedMealType(),
            amount: servingAmount,
            ...serving,
        };
        this.dispatchEvent(createLogFoodEvent(detail));
    }

    /**
     * For an OFF product, look up the matching food_item by barcode (the
     * server's sync resolver ensures barcodes are unique). Create one from
     * the OFF data on first encounter so future logs reuse the same row.
     */
    private async ensureFoodItemForOffProduct(product: OFFProduct): Promise<FoodItem | null> {
        if (product.barcode) {
            const existing = await HealthService.fetchFoodItemByBarcode(product.barcode);
            if (existing) return existing;
        }
        const defaultGrams = OpenFoodFactsService.getDefaultServing(product);
        return HealthService.createFoodItem({
            canonical_name: product.product_name,
            display_name: product.product_name,
            brand: typeof product.brands === 'string' && product.brands ? product.brands : undefined,
            barcode: product.barcode,
            source: 'openfoodfacts',
            source_ref: product.barcode,
            base_amount: 100,
            base_unit: 'g',
            default_serving_amount: defaultGrams,
            calories_per_base: product.calories_per_100g,
            protein_g_per_base: product.protein_per_100g,
            carbs_g_per_base: product.carbs_per_100g,
            fat_g_per_base: product.fat_per_100g,
            fiber_g_per_base: product.fiber_per_100g,
            sugar_g_per_base: product.sugar_per_100g,
            sodium_mg_per_base: product.sodium_per_100g * 1000,
        });
    }

    private applyMealTypeSelection(): void {
        const mealSelect = this.shadowRoot?.getElementById('meal-type') as HTMLSelectElement | null;
        if (mealSelect) {
            mealSelect.value = this.defaultMealTypeValue ?? getDefaultMealType();
        }
    }

    private getSelectedMealType(): MealType {
        return ((this.shadowRoot?.getElementById('meal-type') as HTMLSelectElement | null)?.value as MealType) ?? getDefaultMealType();
    }
}

customElements.define('food-log-detail', FoodLogDetail);
